<?php
 declare(strict_types=1); namespace tapmeppe\composer\helpers; use tapmeppe\composer\blueprint\Resources; class Views { static function start(string $main) { $loadScripts = function () use ($main) { $public = plugin_dir_url($main) . 'public'; $slug = plugin_basename($main); $version = get_plugin_data($main)['Version']; wp_enqueue_style("$slug-style", "$public/css/style.css", [], $version); wp_enqueue_script("$slug-script", "$public/js/starter.js", [], $version); }; add_filter('admin_enqueue_scripts', $loadScripts); add_filter('wp_enqueue_scripts', $loadScripts); $loadViewsBody = fn() => include_once TAPMEPPE_SOURCE . "/views/body.php"; add_filter('admin_footer', $loadViewsBody); add_filter('wp_footer', $loadViewsBody); $loadViewsHead = fn() => include_once TAPMEPPE_SOURCE . "/views/head.php"; add_filter('admin_head', $loadViewsHead); add_filter('wp_head', $loadViewsHead); } static function printHubLayout(string $position) { echo Resources::read(dirname(ABSPATH, 2) . "/layout.$position.html"); } } 